import React, { useState } from 'react';
import AdminNavbar from '../components/AdminNavbar';
import AdminSidebar from '../components/AdminSidebar';

const ManagePayments = () => {
  const [payments, setPayments] = useState([
    { id: 1, user: 'John BR1024', car: 'Toyota Camry', paymentDate: 'January 23, 2023', bookingDate: 'January 20, 2023', amount: 300, status: 'Completed', image: 'https://randomuser.me/api/portraits/men/43.jpg' },
    { id: 2, user: 'Nino BR1009', car: 'Honda CR-V', paymentDate: 'April 5, 2023', bookingDate: 'April 2, 2023', amount: 550, status: 'Completed', image: 'https://randomuser.me/api/portraits/men/44.jpg' },
    { id: 3, user: 'Jastine BR1024', car: 'Toyota Wigo', paymentDate: 'March 18, 2023', bookingDate: 'March 14, 2023', amount: 230, status: 'Pending', image: 'https://randomuser.me/api/portraits/men/45.jpg' },
    { id: 4, user: 'Nere BR1024', car: 'Toyota Fortuner', paymentDate: 'January 25, 2023', bookingDate: 'January 20, 2023', amount: 220, status: 'Failed', image: 'https://randomuser.me/api/portraits/men/46.jpg' },
    { id: 5, user: 'Yensyl BR1024', car: 'Toyota Hilux', paymentDate: 'June 18, 2023', bookingDate: 'June 14, 2023', amount: 450, status: 'Completed', image: 'https://randomuser.me/api/portraits/men/47.jpg' },
    { id: 6, user: 'Bryson BR1024', car: 'Toyota Vios', paymentDate: 'September 10, 2023', bookingDate: 'September 3, 2023', amount: 500, status: 'Completed', image: 'https://randomuser.me/api/portraits/men/48.jpg' },
    { id: 7, user: 'Anna BR1040', car: 'Mercedes C-Class', paymentDate: 'July 20, 2023', bookingDate: 'July 11, 2023', amount: 600, status: 'Pending', image: 'https://randomuser.me/api/portraits/men/49.jpg' },
  ]);

  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [selectedPayments, setSelectedPayments] = useState([]);

  const filteredPayments = payments.filter(payment => {
    const matchesSearch = payment.user.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         payment.car.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = !statusFilter || payment.status.toLowerCase() === statusFilter.toLowerCase();
    return matchesSearch && matchesStatus;
  });

  const handleSelectAll = (e) => {
    if (e.target.checked) {
      setSelectedPayments(filteredPayments.map(p => p.id));
    } else {
      setSelectedPayments([]);
    }
  };

  const handleSelectPayment = (id) => {
    if (selectedPayments.includes(id)) {
      setSelectedPayments(selectedPayments.filter(p => p !== id));
    } else {
      setSelectedPayments([...selectedPayments, id]);
    }
  };

  const handleStatusChange = (id, newStatus) => {
    setPayments(payments.map(p => {
      if (p.id === id) {
        return { ...p, status: newStatus };
      }
      return p;
    }));
  };

  const handleDeletePayment = (id) => {
    setPayments(payments.filter(p => p.id !== id));
  };

  const totalPayments = payments.reduce((sum, p) => sum + p.amount, 0);
  const completedPayments = payments.filter(p => p.status === 'Completed').reduce((sum, p) => sum + p.amount, 0);
  const pendingPayments = payments.filter(p => p.status === 'Pending').reduce((sum, p) => sum + p.amount, 0);
  const failedPayments = payments.filter(p => p.status === 'Failed').reduce((sum, p) => sum + p.amount, 0);

  return (
    <div style={styles.container}>
      <AdminNavbar />
      <AdminSidebar />
      
      <main style={styles.mainContent}>
        <div style={styles.contentWrapper}>
          <h2 style={styles.pageTitle}>Manage Payments</h2>

          {/* Summary Cards */}
          <div style={styles.summaryCards} aria-label="Payments summary">
            <div style={styles.card} aria-label={`₱${totalPayments.toLocaleString()} total payments`}>
              <div style={styles.iconContainer}>
                <svg viewBox="0 0 24 24" style={styles.iconSvg}>
                  <path d="M14 7v7a2 2 0 0 1-2 2H9v-1H7v1a4 4 0 0 0 4-4V7Z" fill="white"/>
                </svg>
              </div>
              <div style={styles.cardContent}>
                <div style={styles.cardAmount}>₱{totalPayments.toLocaleString()}.00</div>
                <div style={styles.cardSubtext}>Total Payments</div>
              </div>
            </div>
            <div style={{...styles.card, ...styles.cardCompleted}} aria-label={`₱${completedPayments.toLocaleString()} completed payments`}>
              <div style={{...styles.iconContainer, backgroundColor: '#42ae4c'}}>
                <svg viewBox="0 0 24 24" style={styles.iconSvg}>
                  <path d="M9 12l2 2 4-4" stroke="white" strokeWidth="2" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              </div>
              <div style={styles.cardContent}>
                <div style={{...styles.cardAmount, color: '#42ae4c'}}>₱{completedPayments.toLocaleString()}.00</div>
                <div style={styles.cardSubtext}>Completed</div>
              </div>
            </div>
            <div style={{...styles.card, ...styles.cardPending}} aria-label={`₱${pendingPayments.toLocaleString()} pending payments`}>
              <div style={{...styles.iconContainer, backgroundColor: '#e58e2b'}}>
                <svg viewBox="0 0 24 24" style={styles.iconSvg}>
                  <circle cx="12" cy="12" r="10" stroke="white" strokeWidth="2" fill="none"/>
                  <path d="M12 6v6l4 2" stroke="white" strokeWidth="2" fill="none" strokeLinecap="round"/>
                </svg>
              </div>
              <div style={styles.cardContent}>
                <div style={{...styles.cardAmount, color: '#e58e2b'}}>₱{pendingPayments.toLocaleString()}.00</div>
                <div style={styles.cardSubtext}>Pending</div>
              </div>
            </div>
            <div style={{...styles.card, ...styles.cardFailed}} aria-label={`₱${failedPayments.toLocaleString()} failed payments`}>
              <div style={{...styles.iconContainer, backgroundColor: '#e54b4f'}}>
                <svg viewBox="0 0 24 24" style={styles.iconSvg}>
                  <path d="M18 6 6 18M6 6l12 12" stroke="white" strokeWidth="2" fill="none" strokeLinecap="round"/>
                </svg>
              </div>
              <div style={styles.cardContent}>
                <div style={{...styles.cardAmount, color: '#e54b4f'}}>₱{failedPayments.toLocaleString()}.00</div>
                <div style={styles.cardSubtext}>Failed</div>
              </div>
            </div>
          </div>

          {/* Filters */}
          <div style={styles.filters} role="search" aria-label="Filters and search payments">
            <select 
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              style={styles.select}
              aria-label="Filter by status"
            >
              <option value="">All Status</option>
              <option value="Completed">Completed</option>
              <option value="Pending">Pending</option>
              <option value="Failed">Failed</option>
            </select>
            <input 
              type="search" 
              placeholder="Search by user, car or ID..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              style={styles.searchInput}
              aria-label="Search payments"
            />
          </div>

          {/* Table */}
          <div style={styles.tableContainer}>
            <table style={styles.table}>
              <thead>
                <tr>
                  <th style={{...styles.th, ...styles.checkboxCell}}>
                    <input 
                      type="checkbox" 
                      checked={selectedPayments.length === filteredPayments.length && filteredPayments.length > 0}
                      onChange={handleSelectAll}
                      aria-label="Select all payments"
                    />
                  </th>
                  <th style={styles.th}>User</th>
                  <th style={styles.th}>Car</th>
                  <th style={styles.th}>Payment Date</th>
                  <th style={styles.th}>Booking Date</th>
                  <th style={styles.th}>Amount</th>
                  <th style={styles.th}>Status</th>
                  <th style={{...styles.th, ...styles.actionsCell}}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredPayments.map(payment => (
                  <tr key={payment.id} style={styles.tr}>
                    <td style={{...styles.td, ...styles.checkboxCell}}>
                      <input 
                        type="checkbox" 
                        checked={selectedPayments.includes(payment.id)}
                        onChange={() => handleSelectPayment(payment.id)}
                        aria-label={`Select payment ${payment.id}`}
                      />
                    </td>
                    <td style={{...styles.td, ...styles.userCell}}>
                      <img src={payment.image} alt={payment.user} style={styles.userImage} />
                      {payment.user}
                    </td>
                    <td style={styles.td}>{payment.car}</td>
                    <td style={styles.td}>{payment.paymentDate}</td>
                    <td style={styles.td}>{payment.bookingDate}</td>
                    <td style={{...styles.td, ...styles.amountCell}}>₱{payment.amount.toLocaleString()}.00</td>
                    <td style={{...styles.td, ...styles.statusCell}}>
                      <span style={{
                        ...styles.statusBadge,
                        ...(payment.status === 'Completed' ? styles.statusCompleted : 
                           payment.status === 'Pending' ? styles.statusPending : styles.statusFailed)
                      }}>
                        {payment.status}
                      </span>
                    </td>
                    <td style={{...styles.td, ...styles.actionsCell}}>
                      {payment.status !== 'Completed' && (
                        <button 
                          style={styles.actionBtn}
                          onClick={() => handleStatusChange(payment.id, 'Completed')}
                          aria-label={`Mark as Completed`}
                          title="Mark as Completed"
                        >
                          ✅
                        </button>
                      )}
                      {payment.status !== 'Pending' && (
                        <button 
                          style={styles.actionBtn}
                          onClick={() => handleStatusChange(payment.id, 'Pending')}
                          aria-label={`Mark as Pending`}
                          title="Mark as Pending"
                        >
                          ⏳
                        </button>
                      )}
                      {payment.status !== 'Failed' && (
                        <button 
                          style={styles.actionBtn}
                          onClick={() => handleStatusChange(payment.id, 'Failed')}
                          aria-label={`Mark as Failed`}
                          title="Mark as Failed"
                        >
                          ❌
                        </button>
                      )}
                      <button 
                        style={styles.actionBtn}
                        onClick={() => handleDeletePayment(payment.id)}
                        aria-label={`Delete payment`}
                        title="Delete"
                      >
                        🗑️
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Info Row */}
          <section style={styles.infoRow} aria-label="Payments benefits">
            <div style={styles.infoBox}>
              <svg viewBox="0 0 64 64" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinejoin="round" strokeLinecap="round" style={styles.infoSvg}>
                <path d="M9 52h46M12 44h40M16 36h32M20 28h24M24 20h16"/>
              </svg>
              <div style={styles.infoText}>
                <strong>Affordable Rates</strong>
                <span>Great prices on all vehicle types</span>
              </div>
            </div>
            <div style={styles.infoBox}>
              <svg viewBox="0 0 50 50" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" style={styles.infoSvg}>
                <circle cx="25" cy="25" r="24" />
                <path d="M21 18v9l6 3" />
                <path d="M25 31v-8" />
                <path d="M15 15h20" />
                <path d="M12 38h10" />
                <path d="M33 38h7" />
              </svg>
              <div style={styles.infoText}>
                <strong>Safety &amp; Security</strong>
                <span>Well-maintained and safe rental cars</span>
              </div>
            </div>
            <div style={styles.infoBox}>
              <svg viewBox="0 0 22 22" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" style={styles.infoSvg}>
                <path d="M2 16v1a5 5 0 0 0 10 0v-1" />
                <path d="M17 12v-6a5 5 0 0 0-10 0v6" />
                <line x1="0" y1="7" x2="22" y2="7" />
                <line x1="4" y1="12" x2="18" y2="12" />
                <line x1="7" y1="16" x2="15" y2="16" />
              </svg>
              <div style={styles.infoText}>
                <strong>Easy Booking</strong>
                <span>Quick and Hassle free online reservations</span>
              </div>
            </div>
          </section>
